const body = $json.body || $json;
const rawText = (body.raw_text || body.rawText || '').toLowerCase();
const currentStage = body.current_stage || body.currentStage || 'ENTRY';
const targetName = body.target_name || body.targetName || 'unknown-target';
const threadId = body.thread_id || body.threadId || `thread-${Date.now()}`;
const messageId = body.message_id || body.messageId || `msg-${Date.now()}`;
const sourcePlatform = body.source_platform || body.sourcePlatform || 'manual';

return [{
  json: {
    target_name: targetName,
    thread_id: threadId,
    message_id: messageId,
    source_platform: sourcePlatform,
    raw_text: rawText,
    current_stage: currentStage,
    classification_version: '1.0'
  }
}];

const text = $json.raw_text || '';

const ownershipPatterns = [
  /\bour system\b/, /\bour team\b/, /\bour setup\b/, /\bwe\b/, /\bin our\b/, /\bour pipeline\b/, /\bour implementation\b/
];
const uncertaintyPatterns = [
  /not sure/, /unclear/, /uncertain/, /we think/, /probably/, /seems/, /still fail/, /still breaks/, /haven't solved/, /hard to/
];
const boundaryPatterns = [
  /authority drift/, /enforcement gap/, /halt latency/, /execution latency/, /revalidation/, /binding/, /rollback/, /temporal/, /misaligned/, /context reuse/, /interrupt/, /stop authority/
];
const highSignalPatterns = [
  /runtime/, /execution boundary/, /authority/, /control plane/, /rollback/, /enforcement/, /admissibility/, /state/, /constraint/, /governance/
];

const hasMatch = (patterns, input) => patterns.some((r) => r.test(input));

const ownership = hasMatch(ownershipPatterns, text);
const uncertainty = hasMatch(uncertaintyPatterns, text);
const boundary = hasMatch(boundaryPatterns, text);

let signalDepth = 'low';
const highSignalHits = highSignalPatterns.filter((r) => r.test(text)).length;
if (highSignalHits >= 4) signalDepth = 'high';
else if (highSignalHits >= 2) signalDepth = 'medium';

let constraintAwareness = 'low';
if (boundary && uncertainty) constraintAwareness = 'high';
else if (boundary || uncertainty) constraintAwareness = 'medium';

let ownershipPressure = 'low';
if (ownership && uncertainty) ownershipPressure = 'high';
else if (ownership) ownershipPressure = 'medium';

const weights = {
  signalDepth: { low: 0.25, medium: 0.60, high: 0.90 },
  constraintAwareness: { low: 0.20, medium: 0.55, high: 0.90 },
  ownershipPressure: { low: 0.15, medium: 0.55, high: 0.95 }
};

const signalScore = Math.min(Math.max(
  weights.signalDepth[signalDepth] * 0.35 +
  weights.constraintAwareness[constraintAwareness] * 0.35 +
  weights.ownershipPressure[ownershipPressure] * 0.20 +
  (boundary ? 0.10 : 0.0),
0), 1);

const classificationConfidence = Math.min(Math.max(
  0.30 +
  (signalDepth === 'high' ? 0.25 : signalDepth === 'medium' ? 0.15 : 0.05) +
  (constraintAwareness === 'high' ? 0.20 : constraintAwareness === 'medium' ? 0.10 : 0.00) +
  (ownership ? 0.10 : 0.00) +
  (boundary ? 0.10 : 0.00),
0), 1);

const conversionReadiness = Math.min(Math.max(
  (ownership ? 0.30 : 0) +
  (uncertainty ? 0.25 : 0) +
  (boundary ? 0.25 : 0) +
  signalScore * 0.10 +
  classificationConfidence * 0.10,
0), 1);

let targetType = 'E';
let responseMode = 'drop';
let nextAction = 'drop';
let recommendedRoute = 'drop';
let pressureCeiling = 'none';
let responseType = 'noise';

if (signalDepth === 'high' && constraintAwareness === 'high' && ownershipPressure === 'high') {
  targetType = 'A';
  responseMode = 'convert';
  nextAction = conversionReadiness >= 0.72 ? 'convert' : 'push';
  recommendedRoute = 'conversion_engine';
  pressureCeiling = 'high';
  responseType = ownership && uncertainty ? 'ownership' : 'constraint_acknowledgement';
} else if (signalDepth === 'high' && (constraintAwareness === 'high' || constraintAwareness === 'medium')) {
  targetType = 'B';
  responseMode = ownership ? 'align' : 'align';
  nextAction = ownership ? 'push' : 'align';
  recommendedRoute = 'architect_intelligence';
  pressureCeiling = 'medium';
  responseType = ownership ? 'constraint_acknowledgement' : 'peer_alignment';
} else if ((signalDepth === 'medium' || constraintAwareness === 'high') && (boundary || uncertainty)) {
  targetType = 'C';
  responseMode = 'shape';
  nextAction = 'shape';
  recommendedRoute = 'dialogue_executor';
  pressureCeiling = 'medium';
  responseType = 'constraint_acknowledgement';
} else if (signalDepth !== 'low' || ownership || uncertainty) {
  targetType = 'D';
  responseMode = 'hold';
  nextAction = 'hold';
  recommendedRoute = 'filter';
  pressureCeiling = 'low';
  responseType = 'curiosity';
}

const constraintDetected = boundary
  ? 'Boundary or enforcement-related failure surface detected.'
  : uncertainty
    ? 'Uncertainty present without explicit boundary language.'
    : 'No meaningful structural constraint detected.';

const authorityGap = boundary
  ? 'Authority, enforcement, or interruption boundary appears underspecified.'
  : 'Authority gap not yet localized.';

return [{
  json: {
    ...$json,
    signals: {
      ownership_signal_detected: ownership,
      uncertainty_signal_detected: uncertainty,
      boundary_exposure_detected: boundary
    },
    scores: {
      signal_score: Number(signalScore.toFixed(2)),
      classification_confidence: Number(classificationConfidence.toFixed(2)),
      conversion_readiness: Number(conversionReadiness.toFixed(2))
    },
    classification_result: {
      target_name: $json.target_name,
      target_type: targetType,
      signal_depth: signalDepth,
      constraint_awareness: constraintAwareness,
      ownership_pressure: ownershipPressure,
      classification_confidence: Number(classificationConfidence.toFixed(2)),
      recommended_route: recommendedRoute,
      response_mode: responseMode,
      core_constraint: constraintDetected,
      authority_gap: authorityGap,
      boundary_exposure: boundary,
      ownership_signal_detected: ownership,
      uncertainty_signal_detected: uncertainty,
      diagnostic_readiness_score: Math.round(conversionReadiness * 100),
      notes: [
        `High-signal keyword hits: ${highSignalHits}`,
        `Ownership signal: ${ownership}`,
        `Uncertainty signal: ${uncertainty}`,
        `Boundary exposure: ${boundary}`
      ]
    },
    target_state: {
      target_id: `${$json.target_name.toLowerCase().replace(/[^a-z0-9]+/g, '-')}-${Date.now()}`,
      target_name: $json.target_name,
      target_type: targetType,
      current_stage: 'CLASSIFY',
      signal_score: Number(signalScore.toFixed(2)),
      constraint_detected: constraintDetected,
      authority_gap: authorityGap,
      conversion_readiness: Number(conversionReadiness.toFixed(2)),
      response_type: responseType,
      assigned_agent: recommendedRoute,
      next_action: nextAction,
      ownership_signal_detected: ownership,
      uncertainty_signal_detected: uncertainty,
      boundary_exposure_detected: boundary,
      classification_confidence: Number(classificationConfidence.toFixed(2)),
      pressure_ceiling: pressureCeiling,
      thread_context: {
        primary_platform: $json.source_platform,
        thread_id: $json.thread_id,
        last_message_id: $json.message_id,
        message_count: 1
      },
      history: [
        {
          timestamp: new Date().toISOString(),
          stage: 'CLASSIFY',
          action: `classified_type_${targetType}`,
          notes: `Route=${recommendedRoute}; next_action=${nextAction}`
        }
      ],
      state_version: '1.0',
      last_updated: new Date().toISOString()
    }
  }
}];

const r = $json.classification_result;
const s = $json.scores;

const summary = {
  target_name: r.target_name,
  target_type: r.target_type,
  signal_score: s.signal_score,
  classification_confidence: s.classification_confidence,
  conversion_readiness: s.conversion_readiness,
  recommended_route: r.recommended_route,
  next_action: $json.target_state.next_action,
  conversion_blocked: !( $json.signals.ownership_signal_detected && $json.signals.uncertainty_signal_detected && $json.signals.boundary_exposure_detected )
};

return [{ json: { ...$json, summary } }];
